#!/usr/bin/env python3
"""
Bug #0001: jax.jit produces wrong output vs jax.disable_jit.

Patterns    : [['normalization', 'crms_norm'], ['constant', 'neg_neg_cancel'], ['branch', 'add_layernorm'], ['constant', 'mul_zero_elim'], ['broadcast', 'hard_clamp_norm'], ['normalization', 'layernorm_residual_add']]
Dependencies: numpy jax
Run         : python unique_0001.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w2 = np.frombuffer(bytes.fromhex("bd378635"), dtype=np.float32).reshape([1])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 64])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 64])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w6 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 64])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 64])
_w9 = np.frombuffer(bytes.fromhex("0000e0bf"), dtype=np.float32).reshape([1])
_w10 = np.frombuffer(bytes.fromhex("0000e03f"), dtype=np.float32).reshape([1])
_w11 = np.frombuffer(bytes.fromhex("00006040"), dtype=np.float32).reshape([1])
_w12 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w13 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w14 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 64])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 64])  # input "model_input"


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_crms_sq = x * x
    n0_crms_ms = jnp.mean(n0_crms_sq, axis=(-1,), keepdims=True)
    n0_crms_add = n0_crms_ms + _w2
    n0_crms_rt = jnp.sqrt(n0_crms_add)
    n0_crms_n = x / n0_crms_rt
    n0_crms_sc = n0_crms_n * _w0
    n0_crms_out = n0_crms_sc * _w1
    n100_nnc_n1 = -n0_crms_out
    n100_nnc_n2 = -n100_nnc_n1
    n100_nnc_out = n100_nnc_n2 * _w3
    n200_aln_add = n100_nnc_out + _w4
    n200_aln_out = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n200_aln_add)) * _w5) + _w6
    n300_mze_mz = n200_aln_out * _w7
    n300_mze_out = n300_mze_mz + _w8
    n400_hcn_cl = jnp.minimum(jnp.maximum(n300_mze_out, jnp.asarray(_w9, dtype=n300_mze_out.dtype)), jnp.asarray(_w10, dtype=jnp.maximum(n300_mze_out, jnp.asarray(_w9, dtype=n300_mze_out.dtype)).dtype))
    n400_hcn_sub = n400_hcn_cl - _w9
    n400_hcn_out = n400_hcn_sub / _w11
    n500_lnradd_ln = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n400_hcn_out)) * _w12) + _w13
    n500_lnradd_out = n500_lnradd_ln + _w14
    return jnp.asarray(n500_lnradd_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)

    with jax.disable_jit():
        ref = np.array(model(x_jax), dtype=np.float32).ravel()

    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(ref.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(ref.astype(np.float64)) + 1e-8))
    print(f"expected (jax.disable_jit): {ref[:6]}")
    print(f"actual   (jax.jit)        : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
